using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class ClassifyTicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class ClassifyTicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> ConfidenceScores { get; set; } = new();
}

namespace TicketClassifier.Models;

/// <summary>
/// Holds the ordered label names extracted from the trained model,
/// used to map Score[] indices to category names at prediction time.
/// </summary>
public class ModelMetadata
{
    public string[] Labels { get; set; } = [];
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService : IHostedService
{
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly IHostEnvironment _env;
    private readonly ModelMetadata _metadata;

    public static readonly string ModelFileName = "ticket-model.zip";

    public ModelTrainingService(
        ILogger<ModelTrainingService> logger,
        IHostEnvironment env,
        ModelMetadata metadata)
    {
        _logger = logger;
        _env = env;
        _metadata = metadata;
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(_env.ContentRootPath, "Data", "tickets.csv");
        var modelPath = Path.Combine(_env.ContentRootPath, "Data", ModelFileName);

        _logger.LogInformation("Loading training data from {DataPath}", dataPath);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Split into train/test sets for honest evaluation
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training multiclass classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation("========== Model Evaluation Metrics ==========");
        _logger.LogInformation("  Micro Accuracy:      {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  Macro Accuracy:      {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  Log Loss:            {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("  Log Loss Reduction:  {LogLossReduction:F4}", metrics.LogLossReduction);

        for (int i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            _logger.LogInformation("  Class {Index} Log Loss: {LogLoss:F4}", i, metrics.PerClassLogLoss[i]);
        }

        _logger.LogInformation("===============================================");

        // Extract ordered label names from the model schema so we can map Score[] to categories
        var labelColumn = model.GetOutputSchema(data.Schema)["Label"];
        var keyValues = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetKeyValues(ref keyValues);
        _metadata.Labels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();

        _logger.LogInformation("Label order: {Labels}", string.Join(", ", _metadata.Labels));

        // Persist model to disk
        mlContext.Model.Save(model, data.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ModelMetadata _metadata;

    public TicketClassifierController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        ModelMetadata metadata)
    {
        _predictionPool = predictionPool;
        _metadata = metadata;
    }

    [HttpPost("classify")]
    public ActionResult<ClassifyTicketResponse> Classify([FromBody] ClassifyTicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(modelName: "TicketClassifier", input);

        var scores = new Dictionary<string, float>();
        for (int i = 0; i < Math.Min(_metadata.Labels.Length, prediction.Score.Length); i++)
        {
            scores[_metadata.Labels[i]] = prediction.Score[i];
        }

        return Ok(new ClassifyTicketResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            ConfidenceScores = scores
        });
    }
}

